UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('drop-squat-to-stick', 'Drop to shallow athletic stance, hands out for balance.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('snap-down-to-stick-control-version', 'Tall-to-athletic stance with slower drop.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('low-box-step-off-to-stick', 'Use floor snap-down first; then very low 4–6 inch step.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('forward-hop-to-stick-low-amplitude', 'Step forward to stick or tiny hop over line.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('lateral-hop-to-stick-low-amplitude', 'Lateral step-to-stick.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('single-leg-hop-to-stick-low-amplitude', 'Single-leg balance hold or step-to-balance, no hop.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('deceleration-step-down-stop-step-stick', 'Forward stop-step only, shallow position.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('jog-to-stick-linear-deceleration', 'Fast walk-to-stick.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('lateral-shuffle-to-stick', 'Side-step to stick.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.'),
  ('backpedal-to-stick', 'Backward walk to freeze.', 'No default sex-based adjustment. Scale by landing quality, symptom tolerance, and supervision needs rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

