INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops position ownership, alignment, and low-speed joint resilience for safer Output and Capacity.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('drop-squat-to-stick', 'Drop Squat to Stick teaches the basic athletic landing position without jump height or horizontal travel — hips back, knees tracking, feet grounded, trunk organized, and stillness after the drop.', 'Belongs in bilateral_landing_control (511) — first landing stick before snap-down, hops, or deceleration.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('snap-down-to-stick-control-version', 'Snap-downs teach rapid organization from tall extension into a stable landing. In Control, the stick is the outcome — rebounding shifts intent toward Output.', 'Belongs in snapdown_landing_control (512) — bridge between slow landing shapes and higher-speed landing work.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('low-box-step-off-to-stick', 'A low step-off adds manageable external drop force while keeping stress controlled — prerequisite to depth drops or rebound work.', 'Belongs in drop_landing_control (513) — low-impact drop landing after floor sticks.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('forward-hop-to-stick-low-amplitude', 'Forward hopping adds horizontal momentum — the athlete must brake forward travel and organize the landing before progressing to broad jumps or sprint deceleration.', 'Belongs in forward_landing_control (514) — first horizontal hop-to-stick after bilateral floor sticks.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('lateral-hop-to-stick-low-amplitude', 'Lateral hop-to-stick introduces frontal-plane force absorption — crucial before lateral bounds, cutting, and change-of-direction work.', 'Belongs in lateral_landing_control (515) — frontal-plane landing after forward hop control.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('single-leg-hop-to-stick-low-amplitude', 'Single-leg hop-to-stick increases demand on ankle, knee, hip, trunk, and pelvis — use only after bilateral landing control and single-leg balance work.', 'Belongs in single_leg_landing_control (516) — unilateral landing after bilateral and balance foundation.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('deceleration-step-down-stop-step-stick', 'This drill teaches braking mechanics without true deceleration speed — step into the ground, lower center of mass, align joints, and freeze the stop.', 'Belongs in braking_position_control (517) — step-based braking before jog-to-stick.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('jog-to-stick-linear-deceleration', 'Jog-to-stick is the low-speed bridge to full deceleration — brake before the stop point with hip/knee/ankle flexion and trunk control.', 'Belongs in linear_deceleration_control (518) — low-speed linear decel after stop-step stick.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('lateral-shuffle-to-stick', 'Lateral shuffle stop teaches frontal-plane braking while maintaining base width and knee/hip alignment — prerequisite to hard lateral cuts.', 'Belongs in lateral_deceleration_control (519) — lateral stop before reactive lateral agility.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.'),
  ('backpedal-to-stick', 'Backpedaling develops coordination and stability; athletes must stop backward movement safely before adding turns or reactive transitions.', 'Belongs in backward_deceleration_control (520) — backward stop before defensive transitions.', '', '', 'Regress height, speed, or distance before reducing stick quality; progress only when every rep ends in a quiet, aligned hold.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();
